package com.abc.studentportal.postgres.entity;
import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="departments") public class DepartmentEntity { @Id private UUID id; @Column(nullable=false,unique=true) private String code; private String name,description; @Column(name="created_at") private Instant createdAt; @Column(name="updated_at") private Instant updatedAt; @Version private long version; protected DepartmentEntity(){} public DepartmentEntity(UUID id,String code,String name,String description,Instant c,Instant u){this.id=id;this.code=code;this.name=name;this.description=description;this.createdAt=c;this.updatedAt=u;} public UUID getId(){return id;} public String getCode(){return code;} public String getName(){return name;} public String getDescription(){return description;} public Instant getCreatedAt(){return createdAt;} public Instant getUpdatedAt(){return updatedAt;} public long getVersion(){return version;} }
